﻿@inherits LayoutComponentBase
@inject WizardState Wizard
@implements IDisposable

<div class="page">
    <div class="sidebar">
        <NavMenu />
    </div>

    <main>
        <div class="top-row px-4">
            @if (Wizard.CurrentStep >= 1 && Wizard.CurrentStep <= WizardState.TotalSteps)
            {
                <div class="d-flex align-items-center gap-2 me-auto">
                    <strong>Step @Wizard.CurrentStep of @WizardState.TotalSteps</strong>
                    @for (int i = 1; i <= WizardState.TotalSteps; i++)
                    {
                        var step = i;
                        <span class="badge @(Wizard.CompletedSteps.Contains(step) ? "bg-success" : step == Wizard.CurrentStep ? "bg-primary" : "bg-secondary")">
                            @step
                        </span>
                    }
                </div>
            }
            <a href="https://learn.microsoft.com/aspnet/core/" target="_blank">About</a>
        </div>

        <article class="content px-4">
            @Body
        </article>
    </main>
</div>

